typedef float fp;

#define LOCAL_MEM_SIZE 1024

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int gridDim_x)
{
    (void)d_Ne;

    int bx = (int)get_group_id(0);
    int tx = (int)get_local_id(0);
    int lsz = (int)get_local_size(0);
    long ei = (long)bx * (long)lsz + (long)tx;
    int nf = lsz - (gridDim_x * lsz - (int)d_no);
    int df = 0;

    __local fp d_psum[LOCAL_MEM_SIZE];
    __local fp d_psum2[LOCAL_MEM_SIZE];

    if (tx < LOCAL_MEM_SIZE) {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * (long)d_mul];
        d_psum2[tx] = d_sums2[ei * (long)d_mul];
    }

    if (nf == lsz) {

        for (int i = 2; i <= lsz; i = 2 * i) {
            if (((tx + 1) % i) == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (lsz - 1)) {
            d_sums[(long)bx * (long)d_mul * (long)lsz] = d_psum[tx];
            d_sums2[(long)bx * (long)d_mul * (long)lsz] = d_psum2[tx];
        }
    }
    else {

        if (bx != (gridDim_x - 1)) {

            for (int i = 2; i <= lsz; i = 2 * i) {
                if (((tx + 1) % i) == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (lsz - 1)) {
                d_sums[(long)bx * (long)d_mul * (long)lsz] = d_psum[tx];
                d_sums2[(long)bx * (long)d_mul * (long)lsz] = d_psum2[tx];
            }
        }
        else {

            for (int i = 2; i <= lsz; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (int i = 2; i <= df; i = 2 * i) {
                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (int i = bx * lsz + df; i < bx * lsz + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[(long)bx * (long)d_mul * (long)lsz] = d_psum[tx];
                d_sums2[(long)bx * (long)d_mul * (long)lsz] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    (void)lambda;
    (void)Nr;

    long ei = (long)get_global_id(0);

    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei % (long)Nc);

        fp Jc = d_I[ei];

        fp dN = d_I[(long)iN[row] * (long)Nc + (long)col] - Jc;
        fp dS = d_I[(long)iS[row] * (long)Nc + (long)col] - Jc;
        fp dW = d_I[(long)row * (long)Nc + (long)jW[col]] - Jc;
        fp dE = d_I[(long)row * (long)Nc + (long)jE[col]] - Jc;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = (fp)0.5f * G2 - (fp)(1.0f / 16.0f) * (L * L);
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) {
            c = (fp)0.0f;
        }
        else if (c > (fp)1.0f) {
            c = (fp)1.0f;
        }

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;
        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    (void)Nr;
    (void)iN;
    (void)jW;

    long ei = (long)get_global_id(0);

    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei % (long)Nc);

        fp cN = d_c[ei];
        fp cS = d_c[(long)iS[row] * (long)Nc + (long)col];
        fp cW = d_c[ei];
        fp cE = d_c[(long)row * (long)Nc + (long)jE[col]];

        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];

        d_I[ei] = d_I[ei] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
